 1→import React from 'react';
 2→import { motion } from 'framer-motion';
 3→
 4→const ReactionBreakdown = ({ data }) => {
 5→    if (!data?.length) return null;
 6→
 7→    const maxCount = Math.max(...data.map((d) => d.count));
 8→
 9→    return (
10→        <div className="analytics-chart-card">
11→            <h3 className="analytics-chart-title">Reaction breakdown</h3>
12→            <div className="analytics-breakdown-list">
13→                {data.map((item, i) => (
14→                    <motion.div
15→                        key={item.type}
16→                        className="analytics-breakdown-row"
17→                        initial={{ opacity: 0, x: -10 }}
18→                        animate={{ opacity: 1, x: 0 }}
19→                        transition={{ duration: 0.25, delay: i * 0.05 }}
20→                    >
21→                        <span className="analytics-breakdown-emoji">{item.type}</span>
22→                        <div className="analytics-breakdown-bar-track">
23→                            <motion.div
24→                                className="analytics-breakdown-bar-fill"
25→                                initial={{ width: 0 }}
26→                                animate={{ width: `${(item.count / maxCount) * 100}%` }}
27→                                transition={{ duration: 0.5, delay: 0.15 + i * 0.05 }}
28→                            />
29→                        </div>
30→                        <span className="analytics-breakdown-count">{item.count}</span>
31→                    </motion.div>
32→                ))}
33→            </div>
34→        </div>
35→    );
36→};
37→
38→export default ReactionBreakdown;
