 1→import { useQuery } from '@tanstack/react-query';
 2→import { getWriterAnalytics } from '../../../API/Api';
 3→import { useAuth } from '../../Context/useAuth';
 4→
 5→const useAnalyticsData = (range = '30d') => {
 6→    const { session } = useAuth();
 7→    const userId = session?.user?.id;
 8→
 9→    return useQuery({
10→        queryKey: ['writerAnalytics', userId, range],
11→        queryFn: () => getWriterAnalytics(session?.access_token, range),
12→        enabled: !!session?.access_token,
13→        staleTime: 1000 * 60 * 5,
14→        refetchOnWindowFocus: false,
15→    });
16→};
17→
18→export default useAnalyticsData;
